import React, { useEffect, useState } from "react";
import API from "../services/api";
import Navbar from "../components/Navbar";

function Staff() {
  const [staffList, setStaffList] = useState([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState(null);

  const [formData, setFormData] = useState({
    name: "",
    role: "",
    phone: "",
    shift: "",
    assignedArea: "",
  });

  useEffect(() => {
    fetchStaff();
  }, []);

  const fetchStaff = async () => {
    try {
      const res = await API.get("/staff");
      setStaffList(res.data);
    } catch (error) {
      console.error("Error fetching staff:", error);
    } finally {
      setLoading(false);
    }
  };

  const resetForm = () => {
    setFormData({
      name: "",
      role: "",
      phone: "",
      shift: "",
      assignedArea: "",
    });
    setEditingId(null);
  };

  const handleChange = (e) => {
    setFormData((prev) => ({
      ...prev,
      [e.target.name]: e.target.value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();

    const payload = {
      name: formData.name,
      role: formData.role,
      phone: formData.phone,
      shift: formData.shift,
      assignedArea: formData.assignedArea,
    };

    try {
      if (editingId) {
        await API.put(`/staff/${editingId}`, payload);
        alert("Staff updated successfully");
      } else {
        await API.post("/staff", payload);
        alert("Staff added successfully");
      }

      resetForm();
      fetchStaff();
    } catch (error) {
      console.error("Error saving staff:", error);

      if (error.response?.data) {
        const data = error.response.data;
        if (typeof data === "object") {
          const firstError = Object.values(data)[0];
          alert(firstError);
        } else {
          alert("Failed to save staff");
        }
      } else {
        alert("Failed to save staff");
      }
    }
  };

  const handleEdit = (staff) => {
    setEditingId(staff.id);
    setFormData({
      name: staff.name || "",
      role: staff.role || "",
      phone: staff.phone || "",
      shift: staff.shift || "",
      assignedArea: staff.assignedArea || "",
    });

    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleDelete = async (id) => {
    const confirmDelete = window.confirm(
      "Are you sure you want to delete this staff record?"
    );
    if (!confirmDelete) return;

    try {
      await API.delete(`/staff/${id}`);
      alert("Staff deleted successfully");
      fetchStaff();
    } catch (error) {
      console.error("Error deleting staff:", error);
      alert("Failed to delete staff");
    }
  };

  return (
    <div style={styles.page}>
      <Navbar />

      <div style={styles.container}>
        <div style={styles.header}>
          <h1 style={styles.title}>Staff Management</h1>
          <p style={styles.subtitle}>
            Add, update, view, and manage zoo staff details from one place.
          </p>
        </div>

        <div style={styles.formCard}>
          <h2 style={styles.cardTitle}>
            {editingId ? "Update Staff" : "Add New Staff"}
          </h2>

          <form onSubmit={handleSubmit} style={styles.formGrid}>
            <input
              type="text"
              name="name"
              placeholder="Staff Name"
              value={formData.name}
              onChange={handleChange}
              style={styles.input}
            />

            <select
              name="role"
              value={formData.role}
              onChange={handleChange}
              style={styles.input}
            >
              <option value="">Select Role</option>
              <option value="Keeper">Keeper</option>
              <option value="Doctor">Doctor</option>
              <option value="Security">Security</option>
              <option value="Cleaner">Cleaner</option>
              <option value="Guide">Guide</option>
              <option value="Manager">Manager</option>
            </select>

            <input
              type="text"
              name="phone"
              placeholder="Phone Number"
              value={formData.phone}
              onChange={handleChange}
              style={styles.input}
            />

            <select
              name="shift"
              value={formData.shift}
              onChange={handleChange}
              style={styles.input}
            >
              <option value="">Select Shift</option>
              <option value="Morning">Morning</option>
              <option value="Evening">Evening</option>
              <option value="Night">Night</option>
            </select>

            <input
              type="text"
              name="assignedArea"
              placeholder="Assigned Area"
              value={formData.assignedArea}
              onChange={handleChange}
              style={styles.input}
            />

            <div style={styles.buttonRow}>
              <button type="submit" style={styles.primaryBtn}>
                {editingId ? "Update Staff" : "Add Staff"}
              </button>

              {editingId && (
                <button
                  type="button"
                  style={styles.cancelBtn}
                  onClick={resetForm}
                >
                  Cancel
                </button>
              )}
            </div>
          </form>
        </div>

        <div style={styles.listSection}>
          <h2 style={styles.cardTitle}>Staff List</h2>

          {loading ? (
            <p>Loading staff...</p>
          ) : staffList.length === 0 ? (
            <p>No staff found.</p>
          ) : (
            <div style={styles.grid}>
              {staffList.map((staff) => (
                <div key={staff.id} style={styles.staffCard}>
                  <h3 style={styles.staffName}>{staff.name}</h3>
                  <p><strong>Role:</strong> {staff.role}</p>
                  <p><strong>Phone:</strong> {staff.phone}</p>
                  <p><strong>Shift:</strong> {staff.shift}</p>
                  <p><strong>Assigned Area:</strong> {staff.assignedArea}</p>

                  <div style={styles.actionRow}>
                    <button
                      style={styles.editBtn}
                      onClick={() => handleEdit(staff)}
                    >
                      Edit
                    </button>

                    <button
                      style={styles.deleteBtn}
                      onClick={() => handleDelete(staff.id)}
                    >
                      Delete
                    </button>
                  </div>
                </div>
              ))}
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

const styles = {
  page: {
    minHeight: "100vh",
    background: "linear-gradient(135deg, #eef2ff, #f8fafc)",
    fontFamily: "Arial, sans-serif",
  },
  container: {
    width: "90%",
    maxWidth: "1200px",
    margin: "0 auto",
    padding: "30px 0 50px",
  },
  header: {
    background: "linear-gradient(135deg, #ffffff, #eff6ff)",
    padding: "30px",
    borderRadius: "20px",
    boxShadow: "0 10px 24px rgba(0,0,0,0.08)",
    marginBottom: "25px",
  },
  title: {
    fontSize: "2.2rem",
    color: "#111827",
    marginBottom: "10px",
  },
  subtitle: {
    color: "#4b5563",
    fontSize: "1rem",
    lineHeight: "1.7",
  },
  formCard: {
    background: "#fff",
    padding: "25px",
    borderRadius: "18px",
    boxShadow: "0 8px 20px rgba(0,0,0,0.08)",
    marginBottom: "30px",
  },
  cardTitle: {
    fontSize: "1.5rem",
    marginBottom: "20px",
    color: "#111827",
